CREATE OR REPLACE FUNCTION reindex_superhero_ids(IN BIGINT) RETURNS VOID LANGUAGE plpgsql AS $$
BEGIN
    -- Create temporary sequence for reindexing
    CREATE TEMPORARY SEQUENCE id_seq_temp MINVALUE 1 START WITH 1 INCREMENT BY 1;

    -- Reset sequence to ensure it starts from 1
    ALTER SEQUENCE id_seq_temp RESTART;

    -- First, offset existing IDs to avoid unique constraint conflicts during update
    UPDATE superhero SET hair_colour_id = hair_colour_id + 2000 WHERE publisher_id = $1;

    -- Reassign contiguous IDs using the sequence, ordered by current hair_colour_id
    UPDATE superhero 
    SET hair_colour_id = nextval('id_seq_temp') 
    WHERE publisher_id = $1
    ORDER BY hair_colour_id;

    -- Clean up temporary sequence
    DROP SEQUENCE id_seq_temp;
END;
$$
